import{_ as o,o as t,c as n,ag as a}from"./chunks/framework.1N8rnUr9.js";const i="/tubebay/assets/connection-oauth-settings.BVlFC6G-.png",r="/tubebay/assets/connection-oauth-google.Dc3P7bwj.png",s="/tubebay/assets/connection-oauth-proxy-token.BIPQ8RuO.png",l="/tubebay/assets/connection-manual-api-key.BtGdco89.png",c="/tubebay/assets/connection-manual-channel-id.87AgGvgk.png",u="/tubebay/assets/dashboard-main.D0b40dgi.png",f=JSON.parse('{"title":"Connection Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/connection.md","filePath":"guide/connection.md","lastUpdated":1775898496000}'),d={name:"guide/connection.md"};function h(g,e,p,y,b,m){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="connection-guide" tabindex="-1">Connection Guide <a class="header-anchor" href="#connection-guide" aria-label="Permalink to &quot;Connection Guide&quot;">​</a></h1><p>To start using TubeBay, you need to connect your YouTube account. This allows the plugin to read your video library and synchronize content to your WooCommerce store.</p><p>TubeBay offers two connection methods: <strong>Google OAuth (Recommended)</strong> and <strong>Manual Setup (Advanced)</strong>.</p><h2 id="google-oauth-2-0-recommended" tabindex="-1">Google OAuth 2.0 (Recommended) <a class="header-anchor" href="#google-oauth-2-0-recommended" aria-label="Permalink to &quot;Google OAuth 2.0 (Recommended)&quot;">​</a></h2><p>This is the easiest and most secure way to connect. It uses our secure authentication proxy to link your account without requiring you to create a personalized Google Cloud project.</p><h3 id="step-1-authorize-via-google" tabindex="-1">Step 1: Authorize via Google <a class="header-anchor" href="#step-1-authorize-via-google" aria-label="Permalink to &quot;Step 1: Authorize via Google&quot;">​</a></h3><ol><li>Navigate to <strong>TubeBay &gt; Settings</strong> in your WordPress dashboard.</li><li>Select the <strong>Google OAuth</strong> tab.</li><li>Click the <strong>Sign in with Google</strong> button. This will open the TubeBay Authorization Proxy.</li></ol><p><img src="'+i+'" alt="Settings Tab Authorization"></p><h3 id="step-2-grant-permissions" tabindex="-1">Step 2: Grant Permissions <a class="header-anchor" href="#step-2-grant-permissions" aria-label="Permalink to &quot;Step 2: Grant Permissions&quot;">​</a></h3><ol><li>Choose the Google Account associated with your YouTube channel.</li><li>Grant TubeBay permission to view your YouTube account (Read-only access).</li><li>Confirm the authorization on the Google security screen.</li></ol><p><img src="'+r+'" alt="Google Authorization Screen"></p><h3 id="step-3-copy-paste-the-access-code" tabindex="-1">Step 3: Copy &amp; Paste the Access Code <a class="header-anchor" href="#step-3-copy-paste-the-access-code" aria-label="Permalink to &quot;Step 3: Copy &amp; Paste the Access Code&quot;">​</a></h3><ol><li>Once authorized, the proxy will display a secure <strong>Access Code</strong>.</li><li>Click the <strong>Copy</strong> button to copy the code to your clipboard.</li><li>Return to your WordPress dashboard and paste the code into the <strong>Access Code</strong> field.</li><li>Click <strong>Connect Account</strong>.</li></ol><p><img src="'+s+'" alt="Proxy Access Code Page"></p><hr><h2 id="manual-setup-advanced" tabindex="-1">Manual Setup (Advanced) <a class="header-anchor" href="#manual-setup-advanced" aria-label="Permalink to &quot;Manual Setup (Advanced)&quot;">​</a></h2><p>If you prefer to use your own Google Cloud project and API credentials, you can use the Manual method.</p><h3 id="how-to-get-your-google-cloud-api-key" tabindex="-1">How to get your Google Cloud API Key: <a class="header-anchor" href="#how-to-get-your-google-cloud-api-key" aria-label="Permalink to &quot;How to get your Google Cloud API Key:&quot;">​</a></h3><ol><li>Visit the <a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">Google Cloud Console</a>.</li><li>Create a new project (e.g., &quot;My TubeBay App&quot;).</li><li>Navigate to <strong>APIs &amp; Services &gt; Library</strong> and search for <strong>YouTube Data API v3</strong>. Click <strong>Enable</strong>.</li><li>Go to <strong>APIs &amp; Services &gt; Credentials</strong>.</li><li>Click <strong>+ Create Credentials</strong> and select <strong>API Key</strong>.</li><li>Copy the generated key. (We recommend restricting this key to your website URL for extra security).</li></ol><p><img src="'+l+'" alt="GCP API Key Generation"></p><h3 id="how-to-find-your-youtube-channel-id" tabindex="-1">How to find your YouTube Channel ID: <a class="header-anchor" href="#how-to-find-your-youtube-channel-id" aria-label="Permalink to &quot;How to find your YouTube Channel ID:&quot;">​</a></h3><ol><li>Sign in to your YouTube account.</li><li>Visit your <a href="https://www.youtube.com/account_advanced" target="_blank" rel="noreferrer">YouTube Account Advanced Settings</a>.</li><li>Locate the <strong>Channel ID</strong> field (it starts with <code>UC...</code>).</li><li>Click <strong>Copy</strong>.</li></ol><p><img src="'+c+'" alt="YouTube Advanced Settings - Channel ID"></p><h3 id="finalizing-manual-connection" tabindex="-1">Finalizing Manual Connection: <a class="header-anchor" href="#finalizing-manual-connection" aria-label="Permalink to &quot;Finalizing Manual Connection:&quot;">​</a></h3><ol><li>In WordPress, go to <strong>TubeBay &gt; Settings</strong> and select the <strong>Manual Setup</strong> tab.</li><li>Enter your <strong>YouTube Channel ID</strong> and <strong>Google Cloud API Key</strong>.</li><li>Click <strong>Save &amp; Connect</strong>.</li></ol><hr><h2 id="verifying-the-connection" tabindex="-1">Verifying the Connection <a class="header-anchor" href="#verifying-the-connection" aria-label="Permalink to &quot;Verifying the Connection&quot;">​</a></h2><p>Once connected, TubeBay will attempt to fetch your channel details. If successful, you will see your Channel Name and Profile Image in the dashboard.</p><p><img src="'+u+'" alt="Successful Connection Dashboard"></p><div class="tip custom-block"><p class="custom-block-title">Security Note</p><p>We never store your Google password. TubeBay only uses secure tokens (OAuth) or public API keys (Manual) to read your public video data.</p></div>',30)])])}const A=o(d,[["render",h]]);export{f as __pageData,A as default};
